import Vue from 'vue';
import Vuex from 'vuex';
import createPersistedState from 'vuex-persistedstate'

Vue.use(Vuex);

export default new Vuex.Store({
    plugins: [
      createPersistedState() // SPA 새로고침시 상태값 초기화 문제 해결
    ],
    state: {
      isLogin: false,
      user: null,
      dashboardMenuNum: 0,
      dashboardRightMenuView: true,
    },
    mutations: {
      SET_LOGIN(state, booleanValue) {
        state.isLogin = booleanValue
      },
      SET_USER(state, userObject) {
          state.user = userObject
      },  
      SET_DASHBOARD_MENU(state, selectNum) {
          state.dashboardMenuNum = selectNum;
      },
      SET_RIGHT_MENU_OPEN(state, value) {
          state.dashboardRightMenuView = value;
      },
    },
    getters: {
      isLogin(state) {
        return state.isLogin
      },
      user(state) {
          return state.user
      },
    },
    actions: {},
    modules: {},
});
