<template>
    <div class="map_wrap">
        <div class="btn_sample">
            <button @click="clearAll()">clear</button>
            <button @click="drawRadar()">draw-radar</button>
            <button @click="drawArea()">draw-area</button>
            <button @click="drawDrone('enemy')">적군 드론</button>
            <button @click="drawDrone('friend')">아군 드론</button>
            <button @click="drawDrone('unknown')">알수없음 드론</button>
            <!-- <button @click="refreshDrone()">refresh-drone</button> -->
        </div>
        <button v-if="isInfoPopup.view" class="btn_info_popup on" :class="isInfoPopup.right ? 'right' : ''" @click="infoPopupView(false)"></button>
        <button v-else class="btn_info_popup off" :class="isInfoPopup.right ? 'right' : ''" @click="infoPopupView(true)"></button>
        <!-- <button class="btn_map satelite" @click="mapSatelite()"></button> -->
        <button class="btn_map normal" @click="mapNormal()"></button>
        <div id="map" />
        <!-- 드론 컨트롤 메뉴 -->
        <div class="drone_control_menu" v-show="controlMenuView">
            <button class="control on" :disabled="allDroneControlOff" :class="allDroneControl ? 'active' : ''" @click="allDroneControlFnc(true)">
                전체켜기
            </button>
            <button class="control off" :disabled="allDroneControl" :class="allDroneControlOff ? 'active' : ''" @click="allDroneControlOffFnc(true)">
                전체끄기
            </button>

            <ul class="drone_list">
                <li v-for="(drone, index) in droneDomeList" :key="index" :class="drone.power ? 'active' : ''">
                    <button @click="popupDroneOpen(drone)">
                        {{ drone.name }}
                    </button>
                </li>
            </ul>
        </div>
        <div v-show="isInfoPopup.view" class="drone_info_popup" :style="`max-height: ${this.mapHeight - 110}px`">
            <div class="list">
                <masonry-wall :items="droneInfoList" :min-columns="2" :column-width="250" :gap="10" :rtl="true">
                    <template #default="{ item }">
                        <div
                            class="popup"
                            :class="
                                selectDetailDroneId === ''
                                    ? `${item.type}`
                                    : selectDetailDroneId !== item.id
                                    ? `${item.type} opacity`
                                    : `${item.type} select`
                            "
                        >
                            <button class="btn_x" @click="popupInfoDelete(item.id)" />
                            <div v-if="item.type === 'enemy'" class="enemy">
                                <p class="drone_name">{{ item.name }}</p>
                                <ul>
                                    <li>식별 ID: 11</li>
                                    <li>드론 ID:{{ item.id }}</li>
                                    <li>거리: 11</li>
                                </ul>
                            </div>
                            <div v-if="item.type === 'friend'" class="friend">
                                <p class="drone_name">{{ item.name }}</p>
                                <ul>
                                    <li>식별 ID: 11</li>
                                    <li>드론 ID:{{ item.id }}</li>
                                    <li>거리: 11</li>
                                    <li>고도: 11</li>
                                    <li>각도: 11</li>
                                    <li>속도: 11</li>
                                    <li>조종자 위도: 11</li>
                                    <li>조종자 경도: 11</li>
                                    <li>조종자 거리: 11</li>
                                    <li>탐지 시간: 11</li>
                                </ul>
                            </div>
                            <div v-if="item.type === 'unknown'" class="unknown">
                                <p class="drone_name">{{ item.name }}</p>
                                <ul>
                                    <li>식별 ID: 11</li>
                                    <li>드론 ID:{{ item.id }}</li>
                                    <li>거리: 11</li>
                                </ul>
                            </div>
                            <div class="thume" v-show="item.option.thume">
                                <img src="@/assets/map/sample_drone.png" />
                            </div>
                            <ul class="option_list" v-show="!item.option.thume">
                                <li>
                                    <button
                                        class="friend_remove"
                                        :class="item.option.friendRemove ? 'active' : ''"
                                        @click="popupDronInfo(item.id, 'remove')"
                                    />
                                </li>
                                <li>
                                    <button
                                        class="friend_add"
                                        :class="item.option.friendAdd ? 'active' : ''"
                                        @click="popupDronInfo(item.id, 'add')"
                                    />
                                </li>
                                <li>
                                    <button
                                        class="spoofing"
                                        :class="item.option.spoofing ? 'active' : ''"
                                        @click="popupDronInfo(item.id, 'spoofing')"
                                    />
                                </li>
                                <li><button class="eoir" :class="item.option.eoir ? 'active' : ''" @click="popupDronInfo(item.id, 'eoir')" /></li>
                                <li><button class="play" :class="item.option.play ? 'active' : ''" @click="popupDronInfo(item.id, 'play')" /></li>
                                <li><button class="alert" :class="item.option.alert ? 'active' : ''" @click="popupDronInfo(item.id, 'alert')" /></li>
                            </ul>
                            <button class="thume_toggle" :class="item.option.thume ? 'open' : ''" @click="popupInfoThume(item.id)" />
                        </div>
                    </template>
                </masonry-wall>
            </div>
        </div>

        <!-- // 드론 컨트롤 메뉴 -->
        <DroneControlPopup v-if="isDronePopupOpen" :defaultView="true" :selectControlDrone="selectControlDrone" @popupClose="popupDroneClose" />
        <DroneControlOffPopup
            v-if="isDroneOffPopupOpen"
            :defaultView="false"
            :selectControlDrone="selectControlDrone"
            @popupClose="popupDroneClose"
        />
        <AllDroneControlPopup v-if="isAllDronePopupOpen" :defaultView="true" @popupClose="popupAllDrone" />
        <AllDroneControlOffPopup v-if="isAllDroneOffPopupOpen" :defaultView="false" @popupClose="popupAllDroneOff" />
        <RecordList v-if="isRecordPopupOpen" @popupClose="recordPopupClose" />
        <RemoveFriendDronePopup v-if="isRemoveFriendDrone" @popupClose="popupRemoveFriendDrone" />
        <AddFriendDronePopup v-if="isAddFriendDrone" @popupClose="popupAddFriendDrone" />
        <SpooperControlPopup v-if="isSpooperControl" :defaultView="true" @popupClose="popupSpooperControl" />
        <EoIrControlPopup v-if="isEoIrControl" :defaultView="true" @popupClose="popupEoIrControl" />
        <AlertClosePopup v-if="isAlertClose" @popupClose="popupAlertClose" />
        <DroneVideoPopup v-if="isDroneVideo" @popupClose="popupDroneVideo" />
    </div>
</template>

<script>
import $ from 'jquery';
import * as olControl from 'ol/control';
import * as olExtent from 'ol/extent';
import olFeature from 'ol/Feature.js';
import * as olGeometry from 'ol/geom';
import { fromCircle } from 'ol/geom/Polygon';
import olTileLayer from 'ol/layer/Tile';
import olVectorLayer from 'ol/layer/Vector.js';
import olMap from 'ol/Map';
import olOverlay from 'ol/Overlay.js';
import * as olProj from 'ol/proj';
import { get, transform } from 'ol/proj';
import { register } from 'ol/proj/proj4';
import { XYZ } from 'ol/source';
import olVectorSource from 'ol/source/Vector.js';
import * as olStyle from 'ol/style';
import olWMTSTileGrid from 'ol/tilegrid/WMTS.js';
import olView from 'ol/View.js';
import proj4 from 'proj4';
// import ScaleLine from 'ol/control/ScaleLine.js';
// import Attribution from 'ol/control/Attribution.js';
// import Control from 'ol/control/Control.js';
// import {defaults} from 'ol/control/defaults';
import AddFriendDronePopup from '@/components/popup/common/AddFriendDrone';
import AlertClosePopup from '@/components/popup/common/AlertClose';
import { default as AllDroneControlOffPopup, default as AllDroneControlPopup } from '@/components/popup/common/AllDroneControl';
import { default as DroneControlOffPopup, default as DroneControlPopup } from '@/components/popup/common/DroneControl';
import DroneVideoPopup from '@/components/popup/common/DroneVideo';
import EoIrControlPopup from '@/components/popup/common/EoIrControl';
import RemoveFriendDronePopup from '@/components/popup/common/RemoveFriendDrone';
import SpooperControlPopup from '@/components/popup/common/SpooperControl';
import RecordList from '@/components/popup/dashboard/RecordList';
import MasonryWall from '@yeger/vue2-masonry-wall';

export default {
    components: {
        DroneControlPopup,
        DroneControlOffPopup,
        AllDroneControlPopup,
        AllDroneControlOffPopup,
        AddFriendDronePopup,
        RemoveFriendDronePopup,
        SpooperControlPopup,
        EoIrControlPopup,
        AlertClosePopup,
        DroneVideoPopup,
        RecordList,
        MasonryWall,
    },
    props: ['mapHeight'],
    data: () => ({
        map: null,
        isInfoPopup: {
            right: true,
            view: true,
        },
        allDroneControl: false,
        allDroneControlOff: false,
        controlMenuView: false,
        isDronePopupOpen: false,
        isDroneOffPopupOpen: false,
        isAllDronePopupOpen: false,
        isAllDroneOffPopupOpen: false,
        isRecordPopupOpen: false,
        isAddFriendDrone: false,
        isRemoveFriendDrone: false,
        isSpooperControl: false,
        isEoIrControl: false,
        isAlertClose: false,
        isDroneVideo: false,
        path: '/map',
        coordDrone: [],
        droneStrokeColor: ['#FF4949', '#78FF00', '#FFCC00'], // 적군 / 아군 / 알수없음
        activeMenu: 0,
        elDroneDome: [],
        selectControlDrone: {},
        selectDetailDroneId: '',
        enemyDroneList: [
            {
                name: '적군드론이름',
                type: 'enemy',
                id: '111111111',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
        ],
        friendDroneList: [
            {
                name: '아군드론이름',
                type: 'friend',
                id: '2222222222',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
            {
                name: '아군드론이름',
                type: 'friend',
                id: '4',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
            {
                name: '아군드론이름',
                type: 'friend',
                id: '5',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
        ],
        unknownDroneList: [
            {
                name: '알수없는드론이름',
                type: 'unknown',
                id: '333333333',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
            {
                name: '알수없는드론이름',
                type: 'unknown',
                id: '111122',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
            {
                name: '알수없는드론이름',
                type: 'unknown',
                id: '33333133333',
                option: {
                    friendRemove: false,
                    friendAdd: false,
                    spoofing: false,
                    eoir: false,
                    play: false,
                    alert: false,
                    thume: false,
                },
            },
        ],
        droneDomeList: [
            {
                power: false,
                name: '드론돔11',
                signalPower: 20,
                modeAuto: true,
            },
            {
                power: false,
                name: '드론돔2',
                signalPower: 40,
                modeAuto: false,
            },
        ],
        droneInfoList: [],
    }),
    mounted() {
        this.droneInfoList = this.enemyDroneList.concat(this.friendDroneList, this.unknownDroneList);
        this.mapInit();
        this.elDroneDome = [
            `<div class="map_on_icon">
                <img src='${this.path}/area_m.gif'/>
                <p>드론돔 수동</p>
            <div />`,
            `<div class="map_on_icon">
                <img src='${this.path}/area_a.gif'/>
                <p>드론돔 자동</p>
            <div />`,
            `<div class="map_on_icon">
                <img src='${this.path}/center_left.png'/>
                <p>스푸퍼</p>
            <div />`,
        ];
        [
            [
                [126.94497693198056, 37.49677241271912],
                [126.93715655414971, 37.493278530578344],
                [126.93965209538837, 37.492849089747125],
                [126.94260967698453, 37.49234822624572],
                [126.94648917146179, 37.49199871299324],
            ],
            [
                [126.94178529366718, 37.503891782873325],
                [126.93493513179732, 37.494076983342794],
                [126.9375342325481, 37.504460021749686],
            ],
            [
                [126.94041863170825, 37.501458147802516],
                [126.94936567682326, 37.50252990050906],
                [126.94320666474842, 37.49897060136103],
            ],
        ].forEach((item) => {
            const coord = item.map((__) => transform(__, 'EPSG:4326', 'EPSG:5179'));
            this.coordDrone.push(coord);
        });
    },
    computed: {
        menuNumUpdate() {
            return this.$store.state.dashboardMenuNum;
        },
        rightMenuView() {
            return this.$store.state.dashboardRightMenuView;
        },
    },
    watch: {
        menuNumUpdate(num) {
            this.activeMenu = num;
            this.controlMenuView = this.activeMenu === 4;

            if (this.activeMenu === 1) {
                this.isRecordPopupOpen = true;
            } else if (this.activeMenu === 3) {
                this.controlMenuView = true;
            }
        },
        rightMenuView(state) {
            if (state) this.controlMenuView = false;
            this.isInfoPopup.right = state;
        },
    },
    methods: {
        infoPopupView(value) {
            this.isInfoPopup.view = value;
        },
        popupDroneOpen(drone) {
            this.selectControlDrone = drone;
            this.isDronePopupOpen = !drone.power;
            this.isDroneOffPopupOpen = drone.power;
        },
        popupDroneClose(value) {
            this.isDronePopupOpen = this.isDroneOffPopupOpen = false;
        },
        // 전체 켜기
        popupAllDrone(value) {
            // value = true 는 사용 / false 취소
            if (value) {
                this.allDroneControl = false;
                this.allDroneControlOff = true;

                this.droneDomeList.forEach((item) => {
                    item.power = true;
                });
            }
            this.isAllDronePopupOpen = false;
        },
        // 전체 끄기
        popupAllDroneOff(value) {
            // value = true 는 종료 / false 취소
            if (value) {
                this.allDroneControlOff = false;

                this.droneDomeList.forEach((item) => {
                    item.power = false;
                });
            }
            this.isAllDroneOffPopupOpen = false;
        },

        popupRemoveFriendDrone() {
            this.isRemoveFriendDrone = false;
        },
        popupAddFriendDrone() {
            this.isAddFriendDrone = false;
        },
        popupSpooperControl() {
            this.isSpooperControl = false;
        },
        popupEoIrControl() {
            this.isEoIrControl = false;
        },
        popupAlertClose() {
            this.isAlertClose = false;
        },
        popupDroneVideo() {
            this.isDroneVideo = false;
        },

        popupRecordView(view) {
            this.isRecordPopupOpen = view;
            this.popupClose();
        },
        popupDronInfo(droneId, value) {
            this.droneInfoList.forEach((item) => {
                if (item.id === droneId) {
                    if (value === 'remove') {
                        this.isRemoveFriendDrone = true;
                        item.option.friendRemove = !item.option.friendRemove;
                    } else if (value === 'add') {
                        this.isAddFriendDrone = true;
                        item.option.friendAdd = !item.option.friendAdd;
                    } else if (value === 'spoofing') {
                        this.isSpooperControl = true;
                        item.option.spoofing = !item.option.spoofing;
                    } else if (value === 'eoir') {
                        this.isEoIrControl = true;
                        item.option.eoir = !item.option.eoir;
                    } else if (value === 'play') {
                        this.isDroneVideo = true;
                        item.option.play = !item.option.play;
                    } else if (value === 'alert') {
                        this.isAlertClose = true;
                        item.option.alert = !item.option.alert;
                    }
                }
            });
        },
        popupInfoDelete(value) {
            const num = this.droneInfoList.findIndex((item) => item.id === value);
            console.log('num', num);
            this.droneInfoList = this.droneInfoList.splice(num);
        },
        popupInfoThume(value) {
            this.droneInfoList.forEach((item) => {
                if (item.id === value) {
                    item.option.thume = !item.option.thume;
                }
            });
        },
        allDroneControlFnc(state) {
            this.isAllDronePopupOpen = state;
        },
        allDroneControlOffFnc(state) {
            this.isAllDroneOffPopupOpen = state;
        },
        recordPopupClose() {
            this.isRecordPopupOpen = false;
            this.activeMenu = 0;
            this.$store.commit('SET_DASHBOARD_MENU', this.activeMenu);
        },
        // 맵 매서드
        mapInit() {
            proj4.defs(
                'EPSG:5179',
                '+proj=tmerc +lat_0=38 +lon_0=127.5 +k=0.9996 +x_0=1000000 +y_0=2000000 +ellps=GRS80 +towgs84=0,0,0,0,0,0,0 +units=m +no_defs +type=crs',
            );
            register(proj4);

            const EPSG_5179 = get('EPSG:5179');
            EPSG_5179.setExtent([-200000.0, -28024123.62, 31824123.62, 4000000.0]);
            EPSG_5179.getTileGrid = () =>
                new olWMTSTileGrid({
                    origin: olExtent.getTopLeft(EPSG_5179.getExtent()),
                    resolutions: [2088.96, 1044.48, 522.24, 261.12, 130.56, 65.28, 32.64, 16.32, 8.16, 4.08, 2.04, 1.02, 0.51, 0.255],
                });

            // 랜드오버 위도/경도
            const lat = 37.4862285;
            const lng = 126.9631919;

            this.map = new olMap({
                target: 'map',
                controls: olControl.defaults({ zoom: false, attribution: false }).extend([new olControl.ScaleLine({ units: 'metric' })]),
                layers: [
                    // 국토정보지리원 바로e맵 좌표계는 EPSG:5179
                    new olTileLayer({
                        source: new XYZ({
                            attributions: '구현 UI 샘플',
                            projection: EPSG_5179,
                            tileGrid: EPSG_5179.getTileGrid(),
                            tileUrlFunction: (coordinate) => {
                                // 줌레벨보정계수 5
                                const z = coordinate[0] + 5;
                                const x = coordinate[1];
                                const y = coordinate[2];
                                // [LOCAL-MODE] 초기 레이어를 일반지도(korean_map)로 변경.
                                return `https://map.ngii.go.kr/openapi/Gettile.do?apikey=0DCCF3037745F67F165F35B3626FA83F&layer=korean_map&style=korean&tilematrixset=EPSG%3A5179&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fpng&TileMatrix=L${String(z).padStart(2, '0')}&TileCol=${x}&TileRow=${y}`;
                            },
                        }),
                        name: 'ngii-emap',
                    }),

                    new olVectorLayer({
                        source: new olVectorSource(),
                        //			opacity: 0.3,
                        style: {
                            'fill-color': 'rgba(255, 255, 255, 0.7)',
                            'stroke-color': '#ffcc33',
                            'stroke-width': 2,
                            'circle-radius': 7,
                            'circle-fill-color': '#ffcc33',
                        },
                        name: 'vector',
                    }),

                    new olVectorLayer({
                        source: new olVectorSource(),
                        name: 'vector0',
                    }),

                    new olVectorLayer({
                        source: new olVectorSource(),
                        name: 'vector1',
                    }),

                    new olVectorLayer({
                        source: new olVectorSource(),
                        name: 'vector2',
                    }),
                ],

                // openlayers 기본 좌표계는 EPSG:3857 ( EPSG:5179로 변경 )
                view: new olView({
                    constrainResolution: true,
                    projection: EPSG_5179,
                    maxResolution: EPSG_5179.getTileGrid().getResolutions()[0],
                    minResolution: EPSG_5179.getTileGrid().getResolutions().slice(-1),
                    extent: EPSG_5179.getExtent(),

                    center: transform([lng, lat], 'EPSG:4326', 'EPSG:5179'),
                    zoom: 6, // 0 ~ 13
                }),
            });

            // this.map.on('click', (event) => {
            //     this.coordDrone.push(event.coordinate);
            //     this.refreshDrone();
            // });
        },
        mapNormal() {
            const EPSG_5179 = get('EPSG:5179');
            const ngii = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'ngii-emap');
            ngii.setOpacity(1.0);
            ngii.setSource(
                new XYZ({
                    attributions: '구현 UI 샘플',
                    projection: EPSG_5179,
                    tileGrid: EPSG_5179.getTileGrid(),
                    tileUrlFunction: (coordinate) => {
                        // 줌레벨보정계수 5
                        const z = String(coordinate[0] + 5).padStart(2, '0');
                        const x = coordinate[1];
                        const y = coordinate[2];
                        // [LOCAL-MODE] 사내 프록시 다운 → NGII 공식 API 직접 호출.
                        return `https://map.ngii.go.kr/openapi/Gettile.do?apikey=0DCCF3037745F67F165F35B3626FA83F&layer=korean_map&style=korean&tilematrixset=EPSG%3A5179&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fpng&TileMatrix=L${z}&TileCol=${x}&TileRow=${y}`;
                    },
                }),
            );
            this.raderStokeChange('black');
        },
        mapSatelite() {
            const EPSG_5179 = get('EPSG:5179');
            const ngii = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'ngii-emap');
            ngii.setOpacity(1.0);
            ngii.setSource(
                new XYZ({
                    attributions: '구현 UI 샘플',
                    projection: EPSG_5179,
                    tileGrid: EPSG_5179.getTileGrid(),
                    tileUrlFunction: (coordinate) => {
                        // 줌레벨보정계수 5
                        const z = coordinate[0] + 5;
                        const x = coordinate[1];
                        const y = coordinate[2];
                        // [LOCAL-MODE] 사내 프록시 다운 → NGII 공식 API 직접 호출 (AIRPHOTO).
                        return `https://map.ngii.go.kr/openapi/Gettile.do?apikey=0DCCF3037745F67F165F35B3626FA83F&layer=AIRPHOTO&style=_null&tilematrixset=EPSG%3A5179&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fjpeg&TileMatrix=L${String(z).padStart(2, '0')}&TileCol=${x}&TileRow=${y}`;
                    },
                }),
            );
            this.raderStokeChange('white');
        },

        raderStokeChange(color) {
            const raderStroke = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'vector')
                .getSource()
                .getFeatures();
            raderStroke.forEach((item) => {
                const getId = item.getId();
                console.log('getId', getId);
                if (!getId) return;
                if (getId.includes('raderStroke_')) {
                    item.setStyle(
                        new olStyle.Style({
                            stroke: new olStyle.Stroke({ color, width: 1 }),
                        }),
                    );
                } else if (getId === 'raderCenter') {
                    item.setStyle(
                        new olStyle.Style({
                            image: new olStyle.Circle({
                                radius: 8,
                                fill: new olStyle.Fill({ color }),
                            }),
                        }),
                    );
                }
            });
        },

        clearAll() {
            let vectorSource;
            ['vector', 'vector0', 'vector1', 'vector2'].forEach((item) => {
                vectorSource = this.map
                    .getLayers()
                    .getArray()
                    .slice(0)
                    .find((__) => __.get('name') === item)
                    .getSource();
                vectorSource.clear();
            });
            this.map.getOverlays().clear();
        },
        drawRadar() {
            // 레이다 중심 좌표
            const center = olProj.transform([126.959598, 37.485113], 'EPSG:4326', 'EPSG:5179');

            // 레이다 원 정보 ( 반지름, 반지름텍스트{좌,우,상,하}, 선색상 )
            const radar_info = [
                [500, '500m', '500m', '500m', '심각 500m', '#ff0000'],
                [1000, '1km', '1km', '1km', '경계 1km', '#ff8000'],
                [2000, '2km', '2km', '2km', '주의 2km', '#ffff00'],
                [3000, '3km', '3km', '3km', '관심 2km', '#0066cc'],
            ];

            const vectorSource = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'vector')
                .getSource();

            // 레이다 라인 표시
            {
                const radius = radar_info[radar_info.length - 1][0];
                [
                    [0, 180],
                    [45, 225],
                    [90, 270],
                    [135, 315],
                ].forEach((angle, idx) => {
                    const start_x = center[0] + radius * Math.cos((angle[0] / 180) * Math.PI);
                    const start_y = center[1] + radius * Math.sin((angle[0] / 180) * Math.PI);
                    const end_x = center[0] + radius * Math.cos((angle[1] / 180) * Math.PI);
                    const end_y = center[1] + radius * Math.sin((angle[1] / 180) * Math.PI);

                    const feature = new olFeature(
                        new olGeometry.LineString([
                            [start_x, start_y],
                            [end_x, end_y],
                        ]),
                    );
                    feature.setStyle(
                        new olStyle.Style({
                            stroke: new olStyle.Stroke({ color: 'white', width: 1 }),
                        }),
                    );
                    feature.setId(`raderStroke_${idx}`);

                    vectorSource.addFeature(feature);
                });
            }
            // var polyCoords = '[3143090.603086447, 9928281.393790578], [3283734.7351311715, 9928892.890016861], [3181003.3691158947, 9849398.380600277], [3143090.603086447, 9928281.393790578]';
            // var pointCoords = '[3229617.319105267, 9916160.39109719]';

            // var polygonFeatureT = new ol.Feature(new ol.geom.Polygon(JSON.parse('[[' + polyCoords + ']]')));
            // var pointFeatureK = new ol.Feature(new ol.geom.Point(JSON.parse(pointCoords)));
            // [
            //     [126.93323264545876, 37.48087061767853],
            //     [126.97606876515718, 37.47915601289635],
            //     [126.98270235177844, 37.50757585844489],
            //     [126.9430164876037, 37.505630179375586],
            // ];

            // 심각 5각형 표시
            {
                // const radius = radar_info[0][0] * 1.2360700000002363;
                // const circle = new olGeometry.Circle(center, radius);
                // const polygon = fromCircle(circle, 5, (18 / 180) * Math.PI);
                // const feature = new olFeature(polygon);
                // const feature = new olFeature(
                //     new olGeometry.Polygon([
                //         [126.93323264545876, 37.48087061767853],
                //         [126.97606876515718, 37.47915601289635],
                //         [126.98270235177844, 37.50757585844489],
                //         [126.9430164876037, 37.505630179375586],
                //     ]),
                // );

                const coords = [
                    [126.93323264545876, 37.48087061767853],
                    [126.97606876515718, 37.47915601289635],
                    [126.98270235177844, 37.50757585844489],
                    [126.9430164876037, 37.505630179375586],
                ];
                const coord_epsg5179 = coords.map((lngLat) => olProj.transform(lngLat, 'EPSG:4326', 'EPSG:5179'));
                const feature = new olFeature(new olGeometry.Polygon([coord_epsg5179]));

                feature.setStyle(
                    new olStyle.Style({
                        stroke: new olStyle.Stroke({ color: 'white', width: 3 }),
                    }),
                );

                vectorSource.addFeature(feature);
            }

            radar_info.forEach((radar) => {
                // 원 표시
                {
                    const circle = new olGeometry.Circle(center, radar[0]);
                    const polygon = fromCircle(circle, 99, 0);

                    const feature = new olFeature(polygon);
                    feature.setId(`radar-${String(radar[0]).padStart(9, '0')}`);
                    feature.setStyle(
                        new olStyle.Style({
                            stroke: new olStyle.Stroke({ color: radar[5], width: 3 }),
                        }),
                    );

                    vectorSource.addFeature(feature);
                }

                // 반지름 표시 ( 각도, 정렬, 텍스트 )
                [
                    ['180', 'center-left', radar[1] + '<br/><br/>'],
                    ['0', 'center-right', radar[2] + '<br/><br/>'],
                    ['90', 'top-center', radar[3]],
                    ['270', 'bottom-center', radar[4]],
                ].forEach((pos) => {
                    const x = center[0] + radar[0] * Math.cos((pos[0] / 180) * Math.PI);
                    const y = center[1] + radar[0] * Math.sin((pos[0] / 180) * Math.PI);

                    const marker = new olOverlay({
                        position: [x, y],
                        positioning: pos[1],
                        element: $(`<small style='color:white; cursor:default;'>${pos[2]}</small>`)[0],
                        stopEvent: false,
                    });
                    this.map.addOverlay(marker);
                });
            });

            // 레이다 중심 포인트 표시
            {
                const feature = new olFeature(new olGeometry.Point(center));
                feature.setStyle(
                    new olStyle.Style({
                        image: new olStyle.Circle({
                            radius: 8,
                            fill: new olStyle.Fill({ color: 'white' }),
                        }),
                    }),
                );
                feature.setId(`raderCenter`);

                vectorSource.addFeature(feature);
            }

            // 좌우 중심 아이콘 표시 ( 각도, 정렬, 텍스트 )
            [
                ['180', 'center-center', `<img width=48 height=48 src='${this.path}/center_left.png'/>`],
                ['0', 'center-center', `<img width=48 height=48 src='${this.path}/center_right.png'/>`],
            ].forEach((pos) => {
                const radius = radar_info[radar_info.length - 1][0] / 2;
                const x = center[0] + radius * Math.cos((pos[0] / 180) * Math.PI);
                const y = center[1] + radius * Math.sin((pos[0] / 180) * Math.PI);

                const marker = new olOverlay({
                    position: [x, y],
                    positioning: pos[1],
                    element: $(`${pos[2]}`)[0],
                    stopEvent: false,
                });
                this.map.addOverlay(marker);
            });

            this.map.getView().fit(vectorSource.getExtent(), { duration: 200 });
        },
        drawArea() {
            const vectorSource = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == 'vector')
                .getSource();

            // 구역 정보 ( 중심좌표, 반지름, 정렬, 텍스트, fill색상, 선색상, id )
            [
                [[126.945735, 37.490391], 500, 'center-center', this.elDroneDome[0], 'rgba(255, 128, 0, 0.3)', '#ff8000', 'area-a'],
                [[126.967964, 37.475627], 500, 'center-center', this.elDroneDome[1], 'rgba(51, 255, 255, 0.3)', '#33ffff', 'area-m'],
                [[126.967964, 37.485627], 500, 'center-center', this.elDroneDome[2], 'rgba(51, 255, 0, 0.3)', '#33ffff', 'area-m'],
            ].forEach((area) => {
                const center = transform(area[0], 'EPSG:4326', 'EPSG:5179');

                // 원 표시
                {
                    const circle = new olGeometry.Circle(center, area[1]);
                    const polygon = fromCircle(circle, 99, 0);

                    const feature = new olFeature(polygon);
                    feature.setId(area[6]);
                    feature.setStyle(
                        new olStyle.Style({
                            fill: new olStyle.Fill({ color: area[4] }),
                            stroke: new olStyle.Stroke({ color: area[5], width: 2, lineDash: [5, 5] }),
                        }),
                    );

                    vectorSource.addFeature(feature);
                }

                // 구역 아이콘 표시
                const marker = new olOverlay({
                    position: center,
                    positioning: area[2],
                    element: $(`${area[3]}`)[0],
                    stopEvent: false,
                });
                this.map.addOverlay(marker);
            });

            this.map.getView().fit(vectorSource.getExtent(), { duration: 200 });
        },
        drawDrone(value) {
            let num = 0;
            if (value === 'friend') num = 1;
            else if (value === 'unknown') num = 2;

            let coordDrone = this.coordDrone[num];

            const vectorSource = this.map
                .getLayers()
                .getArray()
                .slice(0)
                .find((__) => __.get('name') == `vector${num}`)
                .getSource();

            // 라인 표시
            {
                const feature = new olFeature({ geometry: new olGeometry.MultiLineString([coordDrone]) });
                feature.setId('coord_drone_line');
                feature.setStyle(
                    new olStyle.Style({
                        stroke: new olStyle.Stroke({ color: this.droneStrokeColor[num], width: 2 }),
                    }),
                );
                vectorSource.addFeature(feature);
            }

            // 점 표시
            {
                const feature = new olFeature({ geometry: new olGeometry.MultiPoint(coordDrone.slice(0)) });
                feature.setId('coord_drone_point');
                feature.setStyle(
                    new olStyle.Style({
                        image: new olStyle.Circle({
                            radius: 4,
                            fill: new olStyle.Fill({ color: this.droneStrokeColor[num] }),
                            stroke: new olStyle.Stroke({ color: this.droneStrokeColor[num], width: 1 }),
                        }),
                    }),
                );
                vectorSource.addFeature(feature);
            }

            // 깃발 아이콘 표시
            {
                const marker = new olOverlay({
                    id: 'flag',
                    position: coordDrone[0],
                    positioning: 'bottom-left',
                    element: $(`<img width=27 height=34 src='${this.path}/flag.png' />`)[0],
                    stopEvent: true,
                });
                this.map.addOverlay(marker);
            }

            // 드론 아이콘 표시
            {
                const element = $(`
                    <div  class='dron_wrap ${value}'>
                        <div droneImg class='drone_img'>
                            <img class="basic" overlay src='${this.path}/drone_${value}.svg'/>
                            <img class="active" overlay src='${this.path}/drone_${value}_on.svg'/>
                        </div>
                        <div info class='drone_info_box enemyDrone'>
                            <span class='ico'></span>
                            <p class='drone_name'>[드론] ${this.enemyDroneList[0].name}</p>
                            <p class='drone_id'>드론 ID : ${this.enemyDroneList[0].id}</p>
                        </div>
                        <div info class='drone_info_box friendDrone'>
                            <span class='ico'></span>
                            <p class='drone_name'>[드론] ${this.friendDroneList[0].name}</p>
                            <p class='drone_id'>드론 ID : ${this.friendDroneList[0].id}</p>
                        </div>
                        <div info class='drone_info_box unknownDrone'>
                            <span class='ico'></span>
                            <p class='drone_name'>[드론] ${this.unknownDroneList[0].name}</p>
                            <p class='drone_id'>드론 ID : ${this.unknownDroneList[0].id}</p>
                        </div>
                        <div info cmd-close class='drone_option'>
                            <ul>
                                <li><button cmd-01 class='sound' /></li>
                                <li><button cmd-02 class='dronedome' /></li>
                                <li><button cmd-03 class='spoofer' /></li>
                                <li><button cmd-04 class='eoir' /></li>
                            </ul>
                        </div>
                    </div>
                `);

                const activeToggle = () => {
                    const droneId =
                        value === 'enemy' ? this.enemyDroneList[0].id : value === 'friend' ? this.friendDroneList[0].id : this.unknownDroneList[0].id;
                    if (this.selectDetailDroneId === droneId) this.selectDetailDroneId = '';
                    else this.selectDetailDroneId = droneId;

                    element.find('[droneImg]').toggleClass('active');
                };

                element.find('[info]').css('display', 'block');
                element.find('[video]').css('display', 'none');
                // 클릭 이벤트 핸들러
                element.find('[overlay]').on('click', () => {
                    // element.find('[info]').css('display', 'block');
                    // element.find('[video]').trigger('click');
                    // console.log('드론 클릭');
                    activeToggle();
                });
                element.find('[cmd-close]').on('click', () => {
                    // console.log('cmd-close 클릭');
                    // element.find('[info]').css('display', 'none');
                    // element.find('[video]').trigger('click');
                    activeToggle();
                });
                element.find('[cmd-01]').on('click', () => {
                    console.log('1번 명령 클릭');
                    element.find('[cmd-01]').toggleClass('off');
                    event.stopPropagation();
                });
                element.find('[cmd-02]').on('click', () => {
                    console.log('2번 명령 클릭');
                    event.stopPropagation();
                });
                element.find('[cmd-03]').on('click', () => {
                    console.log('3번 명령 클릭');
                    event.stopPropagation();
                });
                // element.find('[cmd-04]').on('click', () => {
                //     element.find('[video] img').attr('src', 'http://121.126.86.42:8181/live/CCTV/01/video.mjpg');
                //     element.find('[video]').css('display', 'flex');
                //     event.stopPropagation();
                // });
                // element.find('[video]').on('click', () => {
                //     // element.find('[video] img').attr('src', 'about:blank');
                //     element.find('[video]').css('display', 'none');
                //     event.stopPropagation();
                // });

                // 드론 마커 추가
                const marker = new olOverlay({
                    id: 'drone',
                    position: coordDrone[coordDrone.length - 1],
                    positioning: 'center-center',
                    element: element[0],
                    stopEvent: true,
                });
                this.map.addOverlay(marker);
            }

            this.map.getView().fit(vectorSource.getExtent(), { duration: 200 });
        },
    },
};
</script>

