import Vue from 'vue';
import { createApp } from 'vue';
import App from './App.vue';
import store from './store';
import router from './router';
import vuetify from './plugins/vuetify';
import { TiptapVuetifyPlugin } from 'tiptap-vuetify';
import VueApexCharts from 'vue-apexcharts';

// [LOCAL-MODE] 백엔드 서버 미가동 환경에서 axios 요청이 무한 대기하지 않도록
// 전역 timeout(3초)을 설정하고, 네트워크 에러시 빈 데이터로 resolve 처리한다.
// 이렇게 하면 호출부의 .then(res => res.data.ITEMS) 패턴이 빈 배열을 받아
// 화면 크래시/에러 모달 없이 "데이터 없음" 상태로 정상 렌더링된다.
import axios from 'axios';
axios.defaults.timeout = 3000;
axios.interceptors.response.use(
    (res) => res,
    (err) => {
        const url = err && err.config && err.config.url;
        // eslint-disable-next-line no-console
        console.warn('[LOCAL-MODE] API call short-circuited (server offline):', url);
        return Promise.resolve({
            data: {
                RES_CODE: 0,
                RES_MSG: '[LOCAL-MODE] offline',
                ITEM: {},
                ITEMS: [],
                TOTAL_COUNT: 0,
            },
            status: 200,
            statusText: 'OK (local-mode stub)',
            headers: {},
            config: err && err.config,
        });
    }
);

Vue.config.productionTip = false;
Vue.use(TiptapVuetifyPlugin, {
    // the next line is important! You need to provide the Vuetify Object to this place.
    vuetify, // same as "vuetify: vuetify"
    VueApexCharts,
    // optional, default to 'md' (default vuetify icons before v2.0.0)
    iconsGroup: 'mdi',
});

// eslint-disable-next-line vue/multi-word-component-names
Vue.component('apexchart', VueApexCharts);
new Vue({
    vuetify,
    router,
    store,
    render: (h) => h(App),
}).$mount('#app');
// createApp(App).use(vuetify).use(router).mount('#app');
