import Vue from 'vue';
import VueRouter from 'vue-router';
// import { publicPath } from '../../vue.config'

Vue.use(VueRouter);

const routes = [
    {
        path: '/',
        name: 'Login',
        component: require('@/layout/LoginLayout.vue').default,
        redirect: '/login',
        children: [
            {
                path: '/login',
                name: 'LoginPage',
                component: () => import('@/views/Login/LoginPage.vue'),
            },
        ],
    },
    {
        path: '/dashboard',
        name: 'Dashboard',
        component: require('@/layout/DashboardLayout.vue').default,
        props: true,
        // redirect: '/dashboard/home',
        // children: [
        //     {
        //         path: '/dashboard/home',
        //         name: 'DroneHome',
        //         component: () => import('@/views/Dashboard/DroneHome.vue'),
        //         props: true,
        //     },
        // ],
    },
    {
        path: '/history',
        name: 'History',
        component: require('@/layout/DefaultLayout.vue').default,
        redirect: '/history/detection',
        children: [
            {
                path: '/history/detection/',
                name: 'DetectionDigitalList',
                component: () => import('@/views/History/DetectionList.vue'),
            },
            {
                path: '/history/log',
                name: 'LogList',
                component: () => import('@/views/History/LogList.vue'),
            },
            {
                path: '/history/statistics',
                name: 'StatisticsList',
                component: () => import('@/views/History/StatisticsList.vue'),
            },
        ],
    },
    {
        path: '/setting',
        name: 'Setting',
        component: require('@/layout/DefaultLayout.vue').default,
        redirect: '/setting/connection',
        children: [
            {
                path: '/setting/connection',
                name: 'SystemConnection',
                component: () => import('@/views/Setting/SystemConnection.vue'),
            },
            {
                path: '/setting/map/:id',
                name: 'Map',
                component: () => import('@/views/Setting/MapIndex.vue'),
                children: [
                    {
                        path: '/setting/map/fence',
                        name: 'MapFence',
                        component: () => import('@/views/Setting/Map/MapFence.vue'),
                    },
                    {
                        path: '/setting/map/circle',
                        name: 'MapCircle',
                        component: () => import('@/views/Setting/Map/MapCircle.vue'),
                    },
                    {
                        path: '/setting/map/spooper',
                        name: 'MapSpooper',
                        component: () => import('@/views/Setting/Map/MapSpooper.vue'),
                    },
                    {
                        path: '/setting/map/detection',
                        name: 'MapDetection',
                        component: () => import('@/views/Setting/Map/MapDetection.vue'),
                    },
                ],
            },
            {
                path: '/setting/caution',
                name: 'AlertCaution',
                component: () => import('@/views/Setting/AlertCaution.vue'),
            },
            {
                path: '/setting/identify',
                name: 'PeerIdentify',
                component: () => import('@/views/Setting/PeerIdentify.vue'),
            },
            {
                path: '/setting/device/:id',
                name: 'Map',
                component: () => import('@/views/Setting/DeviceIndex.vue'),
                children: [
                    {
                        path: '/setting/device/scanner',
                        name: 'DeviceScanner',
                        component: () => import('@/views/Setting/Device/DeviceScanner.vue'),
                    },
                    {
                        path: '/setting/device/dronedome',
                        name: 'DeviceDronedome',
                        component: () => import('@/views/Setting/Device/DeviceDronedome.vue'),
                    },
                    {
                        path: '/setting/device/spoofer',
                        name: 'DeviceSpoofer',
                        component: () => import('@/views/Setting/Device/DeviceSpoofer.vue'),
                    },
                ],
            },
            {
                path: '/setting/library',
                name: 'IdentifyLibrary',
                component: () => import('@/views/Setting/IdentifyLibrary.vue'),
            },
            {
                path: '/setting/update',
                name: 'CheckUpdate',
                component: () => import('@/views/Setting/CheckUpdate.vue'),
            },
        ],
    },
    {
        path: '/auth',
        name: 'Auth',
        component: require('@/layout/DefaultLayout.vue').default,
        redirect: '/account',
        children: [
            {
                path: '/account',
                name: 'AccountManage',
                component: () => import('@/views/Account/AccountManage.vue'),
            },
        ],
    },
];

const router = new VueRouter({
    mode: 'history',
    base: '/',
    routes,
});

export default router;
