const dashRecordList = [];

for (let index = 1; index < 12; index++) {
    dashRecordList.push({
        idx: index,
        device: `장비_${index}`,
        model: `모델_${index}`,
        droneId: `idx_${index}`,
        identifyId: `idx_${index}`,
        startTime: `time_${index}`,
        endTime: `time_${index}`,
        regist: false,
        pathView: index % 2 === 0 ? false : true,
    });
}

export default dashRecordList;
