<template>
    <v-app>
        <TopNav />
        <main class="dashboard" ref="dashboard">
            <DashNav />
            <article style="height: inherit;">
                <DroneHome :mapHeight="mapHeight" />
            </article>
        </main>
    </v-app>
</template>

<script>
import TopNav from '@/components/widget/TopNav';
import DashNav from '@/components/widget/DashNav';
import DroneHome from '@/views/Dashboard/DroneHome';
export default {
    components: {
        TopNav,
        DashNav,
        DroneHome,
    },
    data: () => ({
        activeMenu: 0,
        mapHeight: 0,
    }),
    mounted() {
        document.querySelector('html').classList.add('fixed');
        this.handleResize();
        window.addEventListener('resize', this.handleResize);
    },
    beforeDestroy() {
        window.removeEventListener('resize', this.handleResize);
        document.querySelector('html').classList.remove('fixed');
    },
    methods: {
        handleResize() {
            this.mapHeight = `${window.innerHeight - 80}`;
            this.$refs.dashboard.setAttribute('style', `height: ${this.mapHeight}px `);
        },
    },
};
</script>

<style lang="scss" scoped>
main.dashboard {
    min-height: 800px;
}
</style>
