<template>
    <aside>
        <div class="main_menus">
            <ul class="menus">
                <li class="home" :class="activeMenu === 0 ? 'active' : ''" @click="menuActive(0)">HOME</li>
                <li>
                    POWER
                    <v-switch v-model="allDevice" hide-details inset></v-switch>
                </li>
                <li :class="activeMenu === 1 ? 'active' : ''" class="record" @click="menuActive(1)">RECORD</li>
                <li :class="activeMenu === 2 ? 'active' : ''" class="setting" @click="menuActive(2)">SETTING</li>
                <li :class="activeMenu === 3 ? 'active' : ''" class="control" @click="menuActive(3)">CONTROL</li>
            </ul>
            <ul class="observer">
                <li class="eoir">
                    <span>EO/IR</span>
                    <span class="circle"></span>
                    <!-- <span class="circle proceeding"></span> -->
                </li>
                <li class="state" @click="connectionMenuOpen()">
                    <span class="tit">STATE</span>
                    <span class="num">1</span>
                    <span class="circle"></span>
                    <p class="over_txt">드론돔 신호 연결 대기중입니다.</p>
                </li>
            </ul>
        </div>
        <button class="btn_toggle open" @click="toggleMenu()">
            <img src="@/assets/dashboard/ico_arrow.svg" />
        </button>
        <div class="toggle_menus" :class="rightMenuView ? 'open' : 'close'">
            <!-- setting_dronedome -->
            <div class="setting_drone sub" v-show="settingMenuView && this.activeMenu === 2">
                <p class="tit">드론돔</p>
                <div v-for="(drone, index) in droneList" :key="index" class="drone_list">
                    <p class="drone_name">{{ drone.name }}</p>
                    <div class="setting_area">
                        <p class="txt_power">신호 세기 설정</p>
                        <div class="slider">
                            <span>(-)</span>
                            <v-slider v-model="drone.signalPower" :color="fillOpacity.color" hide-details max="90" min="0"></v-slider>
                            <input type="number" max="90" min="0" v-model="drone.signalPower" />
                            <span class="txt_min">0</span>
                            <span class="txt_max">90</span>
                        </div>
                        <div class="mode">
                            <span class="txt_mode">모드 설정</span>
                            <v-switch v-model="drone.modeAuto" :label="drone.modeAuto ? '자동' : '수동'" hide-details inset></v-switch>
                        </div>
                    </div>
                </div>
                <div class="btn_area">
                    <v-btn elevation="3" color="primary"> 확인 </v-btn>
                </div>
            </div>
            <!-- // setting_dronedome -->
            <!-- connection_state -->
            <div class="connection_state sub" v-show="connectionMenuView">
                <p class="tit">연결상태</p>
                <ul class="right_menus mt-7">
                    <li>
                        <span class="ico drone_dome" />
                        <span class="txt">DroneDome</span>
                        <span class="num"><span>1</span></span>
                        <p class="over_txt">드론돔 신호 연결 대기중입니다. 잠시만 기다려주세요.</p>
                    </li>
                    <li>
                        <span class="ico scanner" />
                        <span class="txt">Scanner</span>
                        <span class="num active"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico rader" />
                        <span class="txt">Rader</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico spoofer" />
                        <span class="txt">Spoofer</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico jammer" />
                        <span class="txt">Jammer</span>
                        <span class="num"><span>1</span></span>
                    </li>
                </ul>
            </div>
            <!-- // connection_state -->
            <div>
                <div class="current_time">
                    <ul class="ampm">
                        <li :class="ampm === 'AM' ? 'active' : ''">AM</li>
                        <li :class="ampm === 'PM' ? 'active' : ''">PM</li>
                    </ul>
                    <p class="time">{{ currentTime }}</p>
                    <p class="date">{{ currentDate }}</p>

                    <button class="btn_toggle close" @click="toggleMenu()">
                        <img src="@/assets/dashboard/ico_arrow.svg" />
                    </button>
                </div>
                <ul class="right_menus">
                    <li>
                        <span class="ico friend" />
                        <span class="txt">Friend </span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico enemy" />
                        <span class="txt">Enemy</span>
                        <span class="num active"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico unknown" />
                        <span class="txt">Unknown</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li class="mt-8">
                        <span class="ico drone_dome" />
                        <span class="txt">DroneDome</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico scanner" />
                        <span class="txt">Scanner</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico rader" />
                        <span class="txt">Rader</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico spoofer" />
                        <span class="txt">Spoofer</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico jammer" />
                        <span class="txt">Jammer</span>
                        <span class="num"><span>1</span></span>
                    </li>
                    <li>
                        <span class="ico eo_ir" />
                        <span class="txt">EO / IR</span>
                        <span class="num"><span>1</span></span>
                    </li>
                </ul>
            </div>
        </div>
    </aside>
</template>

<script>
export default {
    data: () => ({
        rightMenuView: true,
        allDevice: false,
        connectionMenuView: false,
        settingMenuView: false,
        activeMenu: 0,
        currentDate: '',
        currentTime: '',
        getTimeFunc: null,
        ampm: '',
        fillOpacity: { color: '#2a85ff' },
        droneList: [
            {
                name: '드론돔1',
                signalPower: 20,
                modeAuto: true,
            },
            {
                name: '드론돔2',
                signalPower: 40,
                modeAuto: false,
            },
        ],
    }),
    computed: {
        menuNumUpdate() {
            return this.$store.state.dashboardMenuNum;
        },
    },
    watch: {
        menuNumUpdate(num) {
            this.activeMenu = num;
            console.log('this.activeMenu', this.activeMenu);
            if (this.activeMenu === 0 || this.activeMenu === 2) this.connectionMenuView;
        },
    },
    beforeMount() {
        this.getTimeFunc = setInterval(() => {
            this.getTime();
        }, 1000);
    },
    mounted() {
        window.scrollTo(0, 0);
    },
    beforeDestroy() {
        clearInterval(this.getTimeFunc);
    },
    methods: {
        toggleMenu() {
            if (this.rightMenuView) {
                this.settingMenuView = this.connectionMenuView = false;
            } else {
                this.menuActive(0);
            }
            this.rightMenuView = !this.rightMenuView;
            this.$store.commit('SET_RIGHT_MENU_OPEN', this.rightMenuView);
        },
        connectionMenuOpen() {
            this.connectionMenuView = this.rightMenuView = true;
            this.settingMenuView = false;
        },
        getTime() {
            const today = new Date();
            // 현재 날짜
            const year = today.getFullYear();
            const month = today.getMonth() + 1;
            const date = today.getDate();
            let stringMonth = '';

            switch (month) {
                case 1:
                    stringMonth = 'Jan';
                    break;
                case 2:
                    stringMonth = 'Feb';
                    break;
                case 3:
                    stringMonth = 'Mar';
                    break;
                case 4:
                    stringMonth = 'Apr';
                    break;
                case 5:
                    stringMonth = 'May';
                    break;
                case 6:
                    stringMonth = 'Jun';
                    break;
                case 7:
                    stringMonth = 'Jul';
                    break;
                case 8:
                    stringMonth = 'Aug';
                    break;
                case 9:
                    stringMonth = 'Sep';
                    break;
                case 10:
                    stringMonth = 'Oct';
                    break;
                case 11:
                    stringMonth = 'Nov';
                    break;
                case 12:
                    stringMonth = 'Dec';
                    break;

                default:
                    break;
            }

            this.currentDate = `${date}. ${stringMonth}. ${year}`;
            // 현재 시간
            const hours = ('0' + today.getHours()).slice(-2);
            const minutes = ('0' + today.getMinutes()).slice(-2);
            const seconds = ('0' + today.getSeconds()).slice(-2);
            this.currentTime = `${hours}:${minutes}:${seconds}`;
            // AM / PM
            if (today.getHours() >= 12) {
                this.ampm = 'PM';
            } else {
                this.ampm = 'AM';
            }
        },
        menuActive(num) {
            console.log('menuActive', num);
            this.activeMenu = num;
            this.$store.commit('SET_DASHBOARD_MENU', this.activeMenu);
            if (this.activeMenu === 2) {
                this.settingMenuView = this.rightMenuView = true;
                this.connectionMenuView = false;
            } else if (this.activeMenu === 3) {
                this.rightMenuView = false;
            }
        },
    },
};
</script>

<style lang="scss" scoped>
