<template>
    <div>
        <div class="popup_wrap">
            <div class="popup_content">
                <p class="popup_title">당일 탐지 기록</p>
                <div>
                    <p class="txt_delete">* 마우스 오른쪽 클릭시 정보 삭제 가능</p>
                    <v-data-table
                        :headers="headers"
                        :items="dataList"
                        :items-per-page="viewPerPage"
                        no-data-text="데이터가 존재하지 않습니다."
                        hide-default-footer
                    >
                        <template #item="{ item, index }">
                            <tr
                                @mousedown.left="selectList(item)"
                                @mousedown.right="deleteList()"
                                :class="selectInfos.includes(item) ? 'active' : ''"
                            >
                                <td>{{ index + 1 }}</td>
                                <td>{{ item.device }}</td>
                                <td>{{ item.model }}</td>
                                <td>{{ item.droneId }}</td>
                                <td>{{ item.identifyId }}</td>
                                <td>{{ item.startTime }}</td>
                                <td>{{ item.endTime }}</td>
                                <td>{{ item.regist }}</td>
                                <td>
                                    <v-btn outlined color="primary" :disabled="item.pathView" elevation="3" @click="popupView(true, item)"
                                        >보기</v-btn
                                    >
                                </td>
                            </tr>
                        </template>
                    </v-data-table>
                    <v-col class="pagination">
                        <v-pagination v-model="pageNo" :length="numOfPages" :total-visible="viewPerPage" />
                    </v-col>
                </div>
                <div class="btn_area">
                    <v-btn outlined plain elevation="3" @click="popupClose">취소</v-btn>
                </div>
            </div>
        </div>
        <ViewRoutePopup v-if="isPopupOpen" :selectInfo="selectInfo" @popupClose="popupView" />
    </div>
</template>
<script>
import dashRecordList from '@/data/dashRecordList';
import ViewRoutePopup from '@/components/popup/history/ViewRoute';
export default {
    components: {
        ViewRoutePopup,
    },
    data: () => ({
        pageNo: 1,
        viewPerPage: 5,
        isPopupOpen: false,
        dataList: [],
        selectInfo: {},
        selectInfos: [],
        headers: [
            { text: 'No', sortable: false },
            { text: '장비', value: 'device', sortable: false },
            { text: '모델명', value: 'model', sortable: false },
            { text: '드론ID', value: 'droneId', sortable: false },
            { text: '식별ID', value: 'identifyId', sortable: false },
            { text: '들어온 시간', value: 'startTime' },
            { text: '나간 시간', value: 'endTime' },
            { text: '등록여부', value: 'regist' },
            { text: '경로보기', value: 'pathView' },
        ],
    }),
    computed: {
        numOfPages() {
            const data = this.dataList.length;
            return Math.ceil(data / this.viewPerPage);
        },
    },
    beforeMount() {
        this.dataList = dashRecordList;
    },
    mounted() {
        //
    },
    methods: {
        popupClose() {
            this.$emit('popupClose', false);
        },
        popupView(view, item) {
            this.selectInfo = item;
            this.isPopupOpen = view;
        },
        selectList(select) {
            const num = this.selectInfos.indexOf(select);
            if (num < 0) {
                this.selectInfos.push(select);
            } else {
                this.selectInfos.splice(num, 1);
            }
        },
        deleteList() {
            alert('this.selectList 삭제');
        },
    },
};
</script>

<style lang="scss" scoped>
.popup_wrap {
    .popup_content {
        width: 800px;
        padding: 0 10px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            border-bottom: 2px solid #ccc;
            font: {
                size: 20px;
                weight: 600;
            }
        }
        .txt_delete {
            margin: 27px 0 6px;
            font: {
                size: 12px;
                weight: 500;
            }
            text-align: right;
            color: #e10000;
        }
        .btn_area {
            @include centerAlign();
            width: 100%;
            border-top: 1px solid #ccc;
        }
    }
}
</style>
