<template>
    <aside>
        <ul :class="this.menuName">
            <li v-for="(menu, index) in menuList" :key="index" class="menu_list">
                <a v-if="menu.subMenu && menu.className === 'map'" class="map sub" :class="isMapAcitve ? 'router-link-active' : ''">
                    <span>{{ menu.title }}</span>
                </a>
                <a
                    v-else-if="menu.subMenu && menu.className === 'device'"
                    class="device sub"
                    :class="isDeviceAcitve ? 'sub router-link-active' : 'sub'"
                >
                    <span>{{ menu.title }}</span>
                </a>
                <router-link v-else :to="menu.router" :class="menu.className">
                    <span>{{ menu.title }}</span>
                </router-link>
                <div v-if="menu.subMenu" class="sub_menu">
                    <ul>
                        <li v-for="(sub, index2) in menu.subMenu" :key="index2" class="menu_sub_list">
                            <router-link :to="sub.router">
                                <span>{{ sub.title }}</span>
                            </router-link>
                        </li>
                    </ul>
                </div>
            </li>
        </ul>
    </aside>
</template>

<script>
import { historyMenu, settingMenu, accountMenu } from '@/data/menuList';

export default {
    components: {
        // ChevronRightIcon,
    },
    data: () => ({
        menuList: [],
        menuName: '',
        isMapAcitve: false,
        isDeviceAcitve: false,
        openSideMenu: false,
    }),
    mounted() {
        this.setSideMenu();
    },
    watch: {
        $route(to, from) {
            this.setSideMenu();
        },
    },
    methods: {
        setSideMenu() {
            this.isDeviceAcitve = this.isMapAcitve = false;
            const currentRoute = this.$route;
            if (currentRoute.path.includes('history')) {
                this.menuName = 'history';
                this.menuList = historyMenu;
            } else if (currentRoute.path.includes('setting')) {
                this.menuName = 'setting';
                this.menuList = settingMenu;
                if (currentRoute.path.includes('map')) {
                    this.isMapAcitve = true;
                } else if (currentRoute.path.includes('device')) {
                    this.isDeviceAcitve = true;
                }
            } else if (currentRoute.path.includes('account')) {
                this.menuName = 'account';
                this.menuList = accountMenu;
            } else {
                this.menuName = '';
                this.menuList = [];
            }
        },
        openMenu() {
            this.openSideMenu = !this.openSideMenu;
        },
    },
};
</script>

<style lang="scss" scoped>
aside {
    position: relative;
    padding: 70px 20px 0;
    box-shadow: -2px 20px 35px 0px #0000004d;
    ul {
        padding-left: 0;
        font: {
            size: 15px;
            weight: 600;
        }
        .menu_list {
            & > a,
            & > span {
                display: block;
                width: 230px;
                height: 50px;
                border-radius: 9px;
                padding-left: 51px;
                color: $color-main02;
                &.router-link-active {
                    background: $color-main01;
                    font: {
                        size: 18px;
                    }
                    color: $color-main04;
                }
                span {
                    @include hCenterAlign();
                    height: inherit;
                    padding-left: 40px;
                }
            }
            & + li {
                margin-top: 10px;
            }
        }
        .menu_sub_list {
            a {
                padding-left: 43px;
                color: $color-main04;
                &.router-link-active {
                    background: url('@/assets/side_arrow.svg') no-repeat 10px center;
                    font: {
                        size: 18px;
                    }
                }
            }
        }
        &.account {
            li {
                a {
                    &.manage {
                        span {
                            background: url('@/assets/account/manage_on.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/account/manage_on.svg');
                            }
                        }
                    }
                }
            }
        }

        &.history {
            li {
                a {
                    &.detection {
                        span {
                            background: url('@/assets/history/detection_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/history/detection_on.svg');
                            }
                        }
                    }
                    &.log {
                        span {
                            background: url('@/assets/history/log_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/history/log_on.svg');
                            }
                        }
                    }
                    &.statistics {
                        span {
                            background: url('@/assets/history/statistics_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/history/statistics_on.svg');
                            }
                        }
                    }
                }
            }
        }
        &.setting {
            li {
                a,
                span {
                    &.connection {
                        span {
                            background: url('@/assets/setting/connection_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/connection_on.svg');
                            }
                        }
                    }
                    &.map {
                        span {
                            background: url('@/assets/setting/map_off.svg') no-repeat 0 center;
                            cursor: default;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/map_on.svg');
                            }
                        }
                    }
                    &.caution {
                        span {
                            background: url('@/assets/setting/warning_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/warning_on.svg');
                            }
                        }
                    }
                    &.identify {
                        span {
                            background: url('@/assets/setting/peer_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/peer_on.svg');
                            }
                        }
                    }
                    &.device {
                        span {
                            background: url('@/assets/setting/device_off.svg') no-repeat 0 center;
                            cursor: default;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/device_on.svg');
                            }
                        }
                    }
                    &.library {
                        span {
                            background: url('@/assets/setting/library_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/library_on.svg');
                            }
                        }
                    }
                    &.update {
                        span {
                            background: url('@/assets/setting/update_off.svg') no-repeat 0 center;
                        }
                        &.router-link-active {
                            span {
                                background-image: url('@/assets/setting/update_on.svg');
                            }
                        }
                    }
                    &.sub {
                        & + .sub_menu {
                            padding: 0 0 20px 49px;
                            border-radius: 0 0 9px 9px;
                            font: {
                                weight: 600;
                            }
                            line-height: 34px;
                            a {
                                display: block;
                                color: $color-main02;
                            }
                        }
                        &.router-link-active {
                            border-radius: 9px 9px 0 0;
                            & + .sub_menu {
                                background-color: $color-main01;
                                a {
                                    color: $color-main04;
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    .dashboard_menu {
        display: none;
        position: absolute;
        top: 0;
        left: 100px;
        height: 100%;
        z-index: 2;
        ul {
            width: 200px;
            height: inherit;
            background: #fff;
        }
        &.open {
            display: block;
            & + .btn_toggle {
                left: 320px;
            }
        }
    }
    .btn_toggle {
        position: absolute;
        top: 50%;
        left: 120px;
        background: red;
        z-index: 2;
    }
}
</style>
